const htmlContent = $node["Infos Site Oficial"].json["data"]; // Substitua por onde está o conteúdo HTML da página

// Função para remover tags HTML e limpar o texto
const extractPlainText = (html) => {
    if (!html) return "";

    // Remove tags <script> e <style> junto com seu conteúdo
    const withoutScriptsAndStyles = html.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, "")
                                        .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, "");

    // Remove todas as demais tags HTML
    const strippedText = withoutScriptsAndStyles.replace(/<\/?[^>]+(>|$)/g, "");

    // Substitui entidades HTML pelos seus equivalentes em texto puro
    const decodedText = strippedText.replace(/&nbsp;/gi, " ")
                                    .replace(/&amp;/gi, "&")
                                    .replace(/&lt;/gi, "<")
                                    .replace(/&gt;/gi, ">")
                                    .replace(/&quot;/gi, "\"")
                                    .replace(/&#39;/gi, "'");

    // Remove múltiplos espaços, tabs e quebras de linha, deixando apenas um espaço
    const cleanedText = decodedText.replace(/\s+/g, " ").trim();

    return cleanedText;
};

// Executa a função para processar o conteúdo HTML
const textoFinal = extractPlainText(htmlContent);

// Retorna o texto limpo como saída deste nó
return {
    textoFinal: textoFinal,
};

